<span class="line">        <span class="token keyword">return</span> users<span class="token punctuation">.</span><span class="token function">slice</span><span class="token punctuation">(</span>start<span class="token punctuation">,</span> start <span class="token operator">+</span> limit<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
